@Value("${nl2sql.schema.vector-enabled:true}")
 private boolean vectorEnabled;

 private final WhitelistMapper whitelistMapper;

 /** 内存缓存的 Schema 信息 (key: tableName, value: SchemaInfo) */
 private final Map<String, SchemaInfo> schemaCache = new HashMap<>();

 /** 内存缓存的向量 (key: tableName, value: embedding vector) */
 private final Map<String, float[]> vectorCache = new HashMap<>();

 /**
 * 初始化：扫描数据库表结构并向量化
 * 
 * 执行时机：
 * 1. 应用启动时 (@PostConstruct)
 * 2. 手动调用 refreshAll()
 */
 @PostConstruct
 public void initOnStartup() {
 log.info("[Schema初始化] 开始扫描数据库表结构...");
 try {
 refreshAll();
 log.info("[Schema初始化] 完成，共处理 {} 张表", schemaCache.size());
 } catch (Exception e) {
 log.error("[Schema初始化] 失败: {}", e.getMessage(), e);
 }
 }

 /**
 * 全量刷新：扫描所有白名单表并重新向量化
 */
 public void refreshAll() {
 log.info("[Schema刷新] 开始全量刷新...");

 // 从数据库白名单表获取允许的表列表
 List<String> allowedTables = getAllowedTablesFromDb();

 if (allowedTables.isEmpty()) {
 log.warn("[Schema刷新] 数据库白名单表 ow_ai_table_whitelist 为空，跳过刷新");
 return;
 }

 log.info("[Schema刷新] 从数据库获取白名单表: {}", allowedTables);

 for (String tableName : allowedTables) {
 try {
 refreshTable(tableName.trim());
 } catch (Exception e) {
 log.error("[Schema刷新] 表 {} 刷新失败: {}", tableName, e.getMessage());
 }
 }

 log.info("[Schema刷新] 完成，当前缓存 {} 张表的 Schema", schemaCache.size());
 }

 /**
 * 从数据库白名单表获取允许的表列表
 */
 private List<String> getAllowedTablesFromDb() {
 try {
 List<Whitelist> whitelist = whitelistMapper.selectList(new QueryWrapper<>());
 if (whitelist == null || whitelist.isEmpty()) {
 return List.of();
 }
 return whitelist.stream()
 .map(Whitelist::getTableName)
 .filter(t -> t != null && !t.trim().isEmpty())
 .collect(Collectors.toList());
 } catch (Exception e) {
 log.error("[Schema] 从数据库获取白名单失败: {}", e.getMessage());
 return List.of();
 }
 }

