toolArgs.newText:
/**
* 全量刷新：扫描所有白名单表并重新向量化
* 
* 重要：此方法会清理已从白名单中删除的表的缓存
*/
public void refreshAll() {
log.info("[Schema刷新] 开始全量刷新...");

// 从数据库白名单表获取允许的表列表
List<String> allowedTables = getAllowedTablesFromDb();

if (allowedTables.isEmpty()) {
log.warn("[Schema刷新] 数据库白名单表 ow_ai_table_whitelist 为空，跳过刷新");
// 清空所有缓存
schemaCache.clear();
vectorCache.clear();
log.info("[Schema刷新] 已清空所有缓存");
return;
}

log.info("[Schema刷新] 从数据库获取白名单表: {}", allowedTables);

// 记录刷新前的缓存表
Set<String> previousTables = new HashSet<>(schemaCache.keySet());
Set<String> allowedSet = new HashSet<>(allowedTables);

// 找出已从白名单中删除的表
Set<String> removedTables = new HashSet<>(previousTables);
removedTables.removeAll(allowedSet);

// 清理已删除表的缓存
for (String removedTable : removedTables) {
schemaCache.remove(removedTable);
vectorCache.remove(removedTable);
log.info("[Schema刷新] 已从缓存移除已删除表: {}", removedTable);
}

// 刷新白名单中的所有表
for (String tableName : allowedTables) {
try {
refreshTable(tableName.trim());
} catch (Exception e) {
log.error("[Schema刷新] 表 {} 刷新失败: {}", tableName, e.getMessage());
}
}

log.info("[Schema刷新] 完成，当前缓存 {} 张表的 Schema", schemaCache.size());
}

