import com.onewindow.aichart.service.RuntimeStatusService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.Map;

/**
 * 项目状态 API 控制器
 * 
 * 提供运行时状态查询接口，供前端 Dashboard 使用
 * 
 * 调用方式：GET /api/v1/projects/{projectId}/status
 */
@Slf4j
@RestController
@RequestMapping("/api/v1/projects")
@RequiredArgsConstructor
public class ProjectStatusController {

    private final RuntimeStatusService runtimeStatusService;

    /**
     * 获取项目运行时状态
     * 
     * GET /api/v1/projects/{projectId}/status
     * 
     * @param projectId 项目ID（用于标识来源）
     * @return 运行时状态数据
     */
    @GetMapping("/{projectId}/status")
    public ResponseEntity<Map<String, Object>> getProjectStatus(@PathVariable String projectId) {
        log.info("[状态API] 获取项目状态: projectId={}", projectId);

        RuntimeStatusService.RuntimeStatus status = runtimeStatusService.getStatus();

        Map<String, Object> result = new HashMap<>();
        result.put("projectId", projectId);
        result.put("code", 200);
        result.put("message", "success");
        result.put("data", Map.of(
                "uptime", status.getUptime(),
                "uptimeSeconds", status.getUptimeSeconds(),
                "queries", Map.of(
                        "total", status.getTotalQueries(),
                        "success", status.getSuccessQueries(),
                        "failed", status.getFailedQueries(),
                        "successRate", String.format("%.2f%%", status.getSuccessRate())
                ),
                "ai", Map.of(
                        "totalCalls", status.getAiCalls(),
                        "totalTokens", status.getAiTokens(),
                        "errors", status.getAiErrors(),
                        "errorRate", String.format("%.2f%%", status.getAiErrorRate())
                ),
                "schema", Map.of(
                        "tableCount", status.getSchemaTableCount(),
                        "initialized", status.isSchemaInitialized(),
                        "lastRefresh", status.getLastSchemaRefresh() != null ? status.getLastSchemaRefresh() : "未刷新"
                )
        ));

        return ResponseEntity.ok(result);
    }

    /**
     * 健康检查接口
     * 
     * GET /api/v1/projects/health
     */
    @GetMapping("/health")
    public ResponseEntity<Map<String, Object>> health() {
        return ResponseEntity.ok(Map.of(
                "status", "UP",
                "service", "onewindow-dv",
                "timestamp", System.currentTimeMillis()
        ));
    }
}

