package com.onewindow.ai.nl2sql.entity;

import com.baomidou.mybatisplus.annotation.*;
import lombok.Data;
import java.time.LocalDateTime;
import java.util.Arrays;
import java.util.Collections;
import java.util.List;
import java.util.stream.Collectors;

/**
 * AI表元数据配置实体
 * 用于增强 NL2SQL 的表匹配精准度
 */
@Data
@TableName("ow_ai_table_metadata")
public class TableMetadata {

    @TableId(type = IdType.AUTO)
    private Long id;

    /**
     * 表名
     */
    @TableField("table_name")
    private String tableName;

    /**
     * 业务显示名称
     */
    @TableField("display_name")
    private String displayName;

    /**
     * 业务描述（给AI看的）
     */
    private String description;

    /**
     * 业务关键词，逗号分隔
     */
    @TableField("business_keywords")
    private String businessKeywords;

    /**
     * 意图标签，逗号分隔
     */
    @TableField("intent_tags")
    private String intentTags;

    /**
     * 优先级 1-100，越大越优先
     */
    private Integer priority;

    /**
     * 是否主表(1=是,0=辅助表)
     */
    @TableField("is_primary")
    private Integer isPrimary;

    /**
     * 示例问题，换行分隔
     */
    @TableField("example_questions")
    private String exampleQuestions;

    @TableField(fill = FieldFill.INSERT)
    private LocalDateTime createdAt;

    @TableField(fill = FieldFill.INSERT_UPDATE)
    private LocalDateTime updatedAt;

    /**
     * 获取关键词列表
     */
    public List<String> getKeywordList() {
        if (businessKeywords == null || businessKeywords.isEmpty()) {
            return Collections.emptyList();
        }
        return Arrays.stream(businessKeywords.split(","))
                .map(String::trim)
                .filter(s -> !s.isEmpty())
                .collect(Collectors.toList());
    }

    /**
     * 获取意图标签列表
     */
    public List<String> getIntentTagList() {
        if (intentTags == null || intentTags.isEmpty()) {
            return Collections.emptyList();
        }
        return Arrays.stream(intentTags.split(","))
                .map(String::trim)
                .filter(s -> !s.isEmpty())
                .collect(Collectors.toList());
    }
}

