package com.onewindow.ai.nl2sql.service;

import com.onewindow.ai.nl2sql.entity.TableMetadata;
import com.onewindow.ai.nl2sql.mapper.TableMetadataMapper;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * 查询意图识别器
 * 基于关键词和意图标签识别用户查询的重点方向
 */
@Slf4j
@Service
public class QueryIntentRecognizer {

    @Autowired
    private TableMetadataMapper tableMetadataMapper;

    /**
     * 识别查询意图并给出表奖励分
     * @param question 用户问题
     * @param candidateTables 候选表列表
     * @return Map<表名, 意图奖励分>
     */
    public Map<String, Double> recognizeIntent(String question, List<String> candidateTables) {
        Map<String, Double> intentBonuses = new HashMap<>();

        for (String tableName : candidateTables) {
            TableMetadata metadata = tableMetadataMapper.findByTableName(tableName);
            if (metadata == null) {
                intentBonuses.put(tableName, 0.0);
                continue;
            }

            double bonus = calculateBonus(question, metadata);
            intentBonuses.put(tableName, bonus);
        }

        return intentBonuses;
    }

    private double calculateBonus(String question, TableMetadata metadata) {
        List<String> keywords = metadata.getKeywordList();
        if (keywords.isEmpty()) return 0.0;

        long hitCount = keywords.stream()
                .filter(question::contains)
                .count();

        // 核心逻辑：如果命中"取号"、"票号"等核心词，且该表是 TICKET 意图
        if (hitCount > 0) {
            double hitRatio = (double) hitCount / keywords.size();

            // 如果命中比例超过50%，或者命中了关键业务词
            if (hitRatio >= 0.5 || hitCount >= 2) {
                return 0.15; // 最高奖励
            }
            return 0.08; // 部分命中
        }

        return 0.0;
    }
}

package com.onewindow.ai.nl2sql.service;

import com.onewindow.ai.nl2sql.entity.TableMetadata;
import com.onewindow.ai.nl2sql.mapper.TableMetadataMapper;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.util.*;
import java.util.stream.Collectors;

/**
 * 混合匹配服务
 * 结合向量分、关键词分、优先级和意图奖励进行综合排序
 */
@Slf4j
@Service
public class HybridMatchService {

    @Autowired
    private TableMetadataMapper tableMetadataMapper;

    @Autowired
    private QueryIntentRecognizer intentRecognizer;

    /**
     * 寻找最优匹配表
     */
    public String findBestMatchTable(String question, Map<String, Double> vectorScores) {
        Map<String, Double> finalScores = calculateFinalScores(question, vectorScores);

        return finalScores.entrySet().stream()
                .max(Map.Entry.comparingByValue())
                .map(Map.Entry::getKey)
                .orElse(null);
    }

    /**
     * 获取得分最高的前 N 张表
     */
    public List<String> findTopNTables(String question, Map<String, Double> vectorScores, int n) {
        Map<String, Double> finalScores = calculateFinalScores(question, vectorScores);

        return finalScores.entrySet().stream()
                .sorted(Map.Entry.<String, Double>comparingByValue().reversed())
                .limit(n)
                .map(Map.Entry::getKey)
                .collect(Collectors.toList());
    }

    private Map<String, Double> calculateFinalScores(String question, Map<String, Double> vectorScores) {
        Map<String, Double> finalScores = new HashMap<>();
        List<String> candidateTables = new ArrayList<>(vectorScores.keySet());

        // 1. 获取意图奖励分
        Map<String, Double> intentBonuses = intentRecognizer.recognizeIntent(question, candidateTables);

        for (String tableName : candidateTables) {
            TableMetadata metadata = tableMetadataMapper.findByTableName(tableName);
            double vectorScore = vectorScores.getOrDefault(tableName, 0.0);

            double keywordScore = 0.0;
            double tagScore = 0.0;
            double priorityScore = 0.5; // 默认中等优先级
            double intentBonus = intentBonuses.getOrDefault(tableName, 0.0);

            if (metadata != null) {
                // 计算关键词分 (命中数 / 总关键词数)
                List<String> keywords = metadata.getKeywordList();
                if (!keywords.isEmpty()) {
                    long hitCount = keywords.stream().filter(question::contains).count();
                    keywordScore = (double) hitCount / keywords.size();
                    // 只要命中一个核心词，权重就大幅提升
                    if (hitCount > 0) keywordScore = Math.max(keywordScore, 0.5); 
                }

                // 优先级分 (0.1 ~ 1.0)
                priorityScore = metadata.getPriority() / 100.0;
            }

            // 核心公式：
            // finalScore = vectorScore * 0.60 + keywordScore * 0.20 + priorityScore * 0.10 + intentBonus
            double finalScore = (vectorScore * 0.60) + (keywordScore * 0.20) + (priorityScore * 0.10) + intentBonus;

            finalScores.put(tableName, finalScore);

            log.info("[NL2SQL-HYBRID] table={}, vector={String.format(\"%.3f\", vectorScore)}, keyword={String.format(\"%.3f\", keywordScore)}, priority={String.format(\"%.3f\", priorityScore)}, intentBonus={String.format(\"%.3f\", intentBonus)}, final={String.format(\"%.3f\", finalScore)}", 
                tableName, vectorScore, keywordScore, priorityScore, intentBonus, finalScore);
        }

        return finalScores;
    }
}

package com.onewindow.ai.nl2sql.service;

import com.onewindow.ai.nl2sql.entity.TableMetadata;
import com.onewindow.ai.nl2sql.mapper.TableMetadataMapper;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;

import java.util.List;

/**
 * Schema 增强服务
 * 构建包含业务语义的 System Prompt
 */
@Service
public class EnhanceSchemaService {

    @Autowired
    private TableMetadataMapper tableMetadataMapper;

    /**
     * 构建增强的 System Prompt 片段
     */
    public String buildEnhancedSystemPrompt(List<String> matchedTables) {
        if (matchedTables == null || matchedTables.isEmpty()) {
            return "";
        }

        StringBuilder sb = new StringBuilder();
        sb.append("\n【数据表业务说明】\n");
        sb.append("以下是本次查询可用的数据表及其业务用途，请严格按照业务语义选择正确的表：\n\n");

        int count = 1;
        for (String tableName : matchedTables) {
            TableMetadata metadata = tableMetadataMapper.findByTableName(tableName);
            if (metadata != null) {
                sb.append(count++).append(". ").append(metadata.getDisplayName())
                  .append("（").append(tableName).append("）\n");
                sb.append("   - 业务用途：").append(metadata.getDescription()).append("\n");
                sb.append("   - 适用查询：").append(metadata.getBusinessKeywords()).append("\n");
                if (metadata.getExampleQuestions() != null && !metadata.getExampleQuestions().isEmpty()) {
                    sb.append("   - 示例问题：").append(metadata.getExampleQuestions().replace("\n", "；")).append("\n");
                }
                sb.append("\n");
            }
        }

        sb.append("【重要约束】\n");
        sb.append("- 只能使用以上列出的表，不得使用其他任何表。\n");
        sb.append("- 如果问题涉及\"取号/叫号/排队\"，必须使用 ow_run_ticket_info，严禁使用统计表。\n");
        sb.append("- 如果问题涉及\"工单/办件/受理\"，优先使用 ow_statis_ticket_info。\n");
        sb.append("- 如需进行表关联（JOIN），只能关联白名单内的表。\n");

        return sb.toString();
    }
}

