package com.onewindow.ai.nl2sql.service;

import com.onewindow.ai.nl2sql.entity.TableMetadata;
import com.onewindow.ai.nl2sql.mapper.TableMetadataMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * 查询意图识别器
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class QueryIntentRecognizer {

    private final TableMetadataMapper tableMetadataMapper;

    /**
     * 识别查询意图，返回各候选表的意图奖励分
     *
     * @param question 用户问题
     * @param candidateTables 候选表名列表
     * @return Map<表名, 意图奖励分>
     */
    public Map<String, Double> recognizeIntent(String question, List<String> candidateTables) {
        Map<String, Double> intentScores = new HashMap<>();

        if (question == null || question.trim().isEmpty() || candidateTables == null || candidateTables.isEmpty()) {
            return intentScores;
        }

        for (String tableName : candidateTables) {
            TableMetadata metadata = tableMetadataMapper.findByTableName(tableName);
            if (metadata == null) {
                intentScores.put(tableName, 0.0);
                continue;
            }

            List<String> keywords = metadata.getKeywordList();
            if (keywords.isEmpty()) {
                intentScores.put(tableName, 0.0);
                continue;
            }

            int matchCount = 0;
            for (String keyword : keywords) {
                if (question.contains(keyword.trim())) {
                    matchCount++;
                }
            }

            double matchRatio = (double) matchCount / keywords.size();
            double bonus = 0.0;

            // 意图奖励规则
            if (matchRatio >= 0.5 || matchCount >= 2) {
                bonus = 0.15; // 强意图匹配
            } else if (matchCount == 1) {
                bonus = 0.08; // 弱意图匹配
            }

            intentScores.put(tableName, bonus);
        }

        return intentScores;
    }
}

package com.onewindow.ai.nl2sql.service;

import com.onewindow.ai.nl2sql.entity.TableMetadata;
import com.onewindow.ai.nl2sql.mapper.TableMetadataMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.*;
import java.util.stream.Collectors;

/**
 * 混合匹配服务 (多维度评分)
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class HybridMatchService {

    private final TableMetadataMapper tableMetadataMapper;
    private final QueryIntentRecognizer queryIntentRecognizer;

    /**
     * 寻找最佳匹配表
     *
     * @param question 用户问题
     * @param vectorScores 向量相似度得分 Map
     * @return 最佳匹配表名
     */
    public String findBestMatchTable(String question, Map<String, Double> vectorScores) {
        List<String> topTables = findTopNTables(question, vectorScores, 1);
        return topTables.isEmpty() ? null : topTables.get(0);
    }

    /**
     * 获取得分最高的 N 张表
     *
     * @param question 用户问题
     * @param vectorScores 向量相似度得分 Map
     * @param n 数量
     * @return 匹配表名列表
     */
    public List<String> findTopNTables(String question, Map<String, Double> vectorScores, int n) {
        if (vectorScores == null || vectorScores.isEmpty()) {
            return Collections.emptyList();
        }

        List<String> candidateTables = new ArrayList<>(vectorScores.keySet());
        Map<String, Double> intentBonuses = queryIntentRecognizer.recognizeIntent(question, candidateTables);

        Map<String, Double> finalScores = new HashMap<>();

        for (String tableName : candidateTables) {
            double vectorScore = vectorScores.getOrDefault(tableName, 0.0);
            double keywordScore = 0.0;
            double tagScore = 0.0;
            double priorityScore = 0.5; // 默认优先级中等
            double intentBonus = intentBonuses.getOrDefault(tableName, 0.0);

            TableMetadata metadata = tableMetadataMapper.findByTableName(tableName);
            if (metadata != null) {
                // 1. 关键词得分 (计算问题中命中该表关键词的比例)
                List<String> keywords = metadata.getKeywordList();
                if (!keywords.isEmpty()) {
                    int matchCount = 0;
                    for (String kw : keywords) {
                        if (question.contains(kw.trim())) {
                            matchCount++;
                        }
                    }
                    keywordScore = (double) matchCount / keywords.size();
                }

                // 2. 标签得分 (简单实现：如果命中意图，也给标签分)
                if (intentBonus > 0) {
                    tagScore = 1.0;
                }

                // 3. 优先级得分
                Integer priority = metadata.getPriority();
                if (priority != null) {
                    priorityScore = priority / 100.0;
                }
            }

            // 最终得分公式
            double finalScore = (vectorScore * 0.60) 
                              + (keywordScore * 0.20) 
                              + (tagScore * 0.10) 
                              + (priorityScore * 0.10) 
                              + intentBonus;

            finalScores.put(tableName, finalScore);

            log.info("[NL2SQL-HYBRID] table={}, vector={String.format(\"%.3f\", vectorScore)}, keyword={String.format(\"%.3f\", keywordScore)}, tag={String.format(\"%.3f\", tagScore)}, priority={String.format(\"%.3f\", priorityScore)}, intentBonus={String.format(\"%.3f\", intentBonus)}, final={String.format(\"%.3f\", finalScore)}", 
                     tableName);
        }

        // 排序并取前 N 个
        return finalScores.entrySet().stream()
                .sorted(Map.Entry.<String, Double>comparingByValue().reversed())
                .limit(n)
                .map(Map.Entry::getKey)
                .collect(Collectors.toList());
    }
}

package com.onewindow.ai.nl2sql.service;

import com.onewindow.ai.nl2sql.entity.TableMetadata;
import com.onewindow.ai.nl2sql.mapper.TableMetadataMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;

import java.util.List;

/**
 * Schema 增强服务
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class EnhanceSchemaService {

    private final TableMetadataMapper tableMetadataMapper;

    /**
     * 构建增强的 System Prompt
     *
     * @param matchedTables 匹配到的表名列表
     * @return 增强的 Prompt 字符串
     */
    public String buildEnhancedSystemPrompt(List<String> matchedTables) {
        if (matchedTables == null || matchedTables.isEmpty()) {
            return "";
        }

        StringBuilder prompt = new StringBuilder();
        prompt.append("\n【数据表业务说明】\n");
        prompt.append("以下是本次查询可用的数据表，请严格按照业务语义选择正确的表：\n\n");

        int index = 1;
        for (String tableName : matchedTables) {
            TableMetadata metadata = tableMetadataMapper.findByTableName(tableName);
            if (metadata == null) {
                continue;
            }

            prompt.append(index++).append(". ").append(metadata.getDisplayName())
                  .append("（").append(tableName).append("）\n");

            prompt.append("   - 业务用途：").append(metadata.getDescription() != null ? metadata.getDescription() : "无").append("\n");
            prompt.append("   - 适用查询关键词：").append(metadata.getBusinessKeywords() != null ? metadata.getBusinessKeywords() : "无").append("\n");

            if (metadata.getExampleQuestions() != null && !metadata.getExampleQuestions().isEmpty()) {
                String examples = metadata.getExampleQuestions().replace("\n", " / ");
                prompt.append("   - 示例问题：").append(examples).append("\n");
            }
            prompt.append("\n");
        }

        prompt.append("【重要约束】\n");
        prompt.append("- 只能使用以上列出的表，不得使用其他任何表\n");
        prompt.append("- 如果问题涉及\"取号/叫号/排队\"，必须使用 ow_run_ticket_info\n");
        prompt.append("- 如果问题涉及\"工单/办件/受理\"，必须使用 ow_statis_ticket_info\n");
        prompt.append("- 如需 JOIN，只能 JOIN 白名单内的表\n");

        return prompt.toString();
    }
}

