type QueryState = "idle" | "loading" | "success" | "empty" | "error";

type ChatMessage = {
  id: string;
  role: "user" | "assistant";
  content: string;
  ts: string;
};

type QueryResult = {
  title: string;
  metric: string;
  period: string;
  data: Array<{ label: string; value: number }>;
};

type AssistantLog = {
  id: string;
  level: "info" | "success" | "error";
  message: string;
  time: string;
};

type ForeignKeyRelation = {
  id: string;
  primaryTable: string;
  primaryField: string;
  foreignTable: string;
  foreignField: string;
};

const NAV_ITEMS: Array<{ key: TabKey; label: string; icon: React.ReactNode }> = [
  { key: "query", label: "智能数据查询", icon: <BarChart3 className="h-4 w-4" /> },
  { key: "assistant", label: "数据助手管理", icon: <Bot className="h-4 w-4" /> },
  { key: "relations", label: "外键关系管理", icon: <Link2 className="h-4 w-4" /> },
];

const mockTables = [
  "users",
  "orders",
  "order_items",
  "products",
  "payments",
  "sessions",
  "events",
];

function uid() {
  return Math.random().toString(36).slice(2, 9);
}

function nowTime() {
  return new Date().toLocaleTimeString("zh-CN", { hour12: false });
}

export default function AIChartDashboard() {
  const [activeTab, setActiveTab] = useState<TabKey>("query");

