function FieldSelect({
  label,
  value,
  onChange,
  options,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  options: string[];
}) {
  return (
    <div>
      <label className="mb-1 block text-sm text-slate-600">{label}</label>
      <select
        value={value}
        onChange={(e) => onChange(e.target.value)}
        className="w-full rounded-xl border border-slate-300 px-3 py-2 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500"
      >
        {options.map((op) => (
          <option key={op} value={op}>
            {op}
          </option>
        ))}
      </select>
    </div>
  );
}

function FieldInput({
  label,
  value,
  onChange,
  placeholder,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
}) {
  return (
    <div>
      <label className="mb-1 block text-sm text-slate-600">{label}</label>
      <input
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full rounded-xl border border-slate-300 px-3 py-2 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-indigo-500"
      />
    </div>
  );
}

function MiniBarChart({
  data,
  metric,
}: {
  data: Array<{ label: string; value: number }>;
  metric: string;
}) {
  const max = Math.max(...data.map((d) => d.value), 1);

  return (
    <div className="rounded-xl border border-slate-200 p-4">
      <div className="mb-3 text-sm text-slate-600">{metric}</div>
      <div className="space-y-3">
        {data.map((d) => {
          const width = `${(d.value / max) * 100}%`;
          return (
            <div key={d.label}>
              <div className="mb-1 flex items-center justify-between text-xs text-slate-500">
                <span>{d.label}</span>
                <span>{d.value.toLocaleString()}</span>
              </div>
              <div className="h-2 rounded-full bg-slate-100">
                <div className="h-2 rounded-full bg-indigo-500" style={{ width }} />
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

package com.onewindow.ai.nl2sql.entity;

import com.baomidou.mybatisplus.annotation.*;
import lombok.Data;

import java.time.LocalDateTime;

/**
 * 逻辑外键关系实体类
 * 用于存储表与表之间的关联关系，帮助 AI 生成更精准的 JOIN 语句
 */
@Data
@TableName("ow_ai_foreign_relation")
public class ForeignRelation {

    @TableId(type = IdType.AUTO)
    private Long id;

    /**
     * 关系名称（如：工单创建者）
     */
    private String name;

    /**
     * 关系别名（如：creator）
     */
    private String alias;

    /**
     * 主表表名
     */
    @TableField("table_name")
    private String tableName;

    /**
     * 主表字段名
     */
    @TableField("column_name")
    private String columnName;

    /**
     * 关联表表名
     */
    @TableField("foreign_table")
    private String foreignTable;

    /**
     * 关联表字段名
     */
    @TableField("foreign_column")
    private String foreignColumn;

    /**
     * 关系描述
     */
    private String description;

    /**
     * 状态：0-禁用，1-启用
     */
    private Integer status;

    @TableField(fill = FieldFill.INSERT)
    @TableField("created_at")
    private LocalDateTime createdAt;

    @TableField(fill = FieldFill.INSERT_UPDATE)
    @TableField("updated_at")
    private LocalDateTime updatedAt;
}

