package com.onewindow.ai.nl2sql.service.impl;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.baomidou.mybatisplus.extension.plugins.pagination.Page;
import com.onewindow.ai.nl2sql.entity.ForeignRelation;
import com.onewindow.ai.nl2sql.mapper.ForeignRelationMapper;
import com.onewindow.ai.nl2sql.service.IForeignRelationService;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.util.StringUtils;

import java.util.List;

/**
 * 逻辑外键关系服务实现类
 */
@Slf4j
@Service
@RequiredArgsConstructor
public class ForeignRelationServiceImpl implements IForeignRelationService {

    private final ForeignRelationMapper foreignRelationMapper;

    @Override
    public Page<ForeignRelation> listPage(int pageNum, int pageSize, String keyword) {
        Page<ForeignRelation> page = new Page<>(pageNum, pageSize);
        LambdaQueryWrapper<ForeignRelation> wrapper = new LambdaQueryWrapper<>();

        if (StringUtils.hasText(keyword)) {
            wrapper.and(w -> w
                .like(ForeignRelation::getName, keyword)
                .or()
                .like(ForeignRelation::getAlias, keyword)
                .or()
                .like(ForeignRelation::getTableName, keyword)
                .or()
                .like(ForeignRelation::getForeignTable, keyword)
            );
        }

        wrapper.orderByDesc(ForeignRelation::getUpdatedAt);
        return foreignRelationMapper.selectPage(page, wrapper);
    }

    @Override
    public List<ForeignRelation> listAll() {
        return foreignRelationMapper.selectList(
            new LambdaQueryWrapper<ForeignRelation>()
                .eq(ForeignRelation::getStatus, 1)
                .orderByDesc(ForeignRelation::getUpdatedAt)
        );
    }

    @Override
    public ForeignRelation getById(Long id) {
        return foreignRelationMapper.selectById(id);
    }

    @Override
    public List<ForeignRelation> listByTableName(String tableName) {
        return foreignRelationMapper.selectList(
            new LambdaQueryWrapper<ForeignRelation>()
                .eq(ForeignRelation::getTableName, tableName)
                .or()
                .eq(ForeignRelation::getForeignTable, tableName)
                .eq(ForeignRelation::getStatus, 1)
        );
    }

    @Override
    public boolean save(ForeignRelation relation) {
        if (relation.getStatus() == null) {
            relation.setStatus(1);
        }
        return foreignRelationMapper.insert(relation) > 0;
    }

    @Override
    public boolean updateById(ForeignRelation relation) {
        return foreignRelationMapper.updateById(relation) > 0;
    }

    @Override
    public boolean deleteById(Long id) {
        return foreignRelationMapper.deleteById(id) > 0;
    }

    @Override
    public boolean deleteByIds(List<Long> ids) {
        return foreignRelationMapper.deleteBatchIds(ids) > 0;
    }
}

