import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * 逻辑外键关系管理控制器
 */
@Slf4j
@RestController
@RequestMapping("/api/v1/relations")
@RequiredArgsConstructor
public class ForeignRelationController {

    private final IForeignRelationService foreignRelationService;

    /**
     * 分页查询关系列表
     */
    @GetMapping
    public ResponseEntity<Map<String, Object>> list(
            @RequestParam(defaultValue = "1") int pageNum,
            @RequestParam(defaultValue = "10") int pageSize,
            @RequestParam(required = false) String keyword) {

        Page<ForeignRelation> page = foreignRelationService.listPage(pageNum, pageSize, keyword);

        Map<String, Object> result = new HashMap<>();
        result.put("code", 200);
        result.put("message", "success");
        result.put("data", page.getRecords());
        result.put("total", page.getTotal());
        result.put("pageNum", page.getCurrent());
        result.put("pageSize", page.getSize());

        return ResponseEntity.ok(result);
    }

    /**
     * 查询所有启用的关系（用于 AI 增强）
     */
    @GetMapping("/all")
    public ResponseEntity<Map<String, Object>> listAll() {
        List<ForeignRelation> list = foreignRelationService.listAll();

        Map<String, Object> result = new HashMap<>();
        result.put("code", 200);
        result.put("message", "success");
        result.put("data", list);

        return ResponseEntity.ok(result);
    }

    /**
     * 获取关系详情
     */
    @GetMapping("/{id}")
    public ResponseEntity<Map<String, Object>> getById(@PathVariable Long id) {
        ForeignRelation relation = foreignRelationService.getById(id);

        Map<String, Object> result = new HashMap<>();
        if (relation != null) {
            result.put("code", 200);
            result.put("message", "success");
            result.put("data", relation);
        } else {
            result.put("code", 404);
            result.put("message", "Relation not found");
        }

        return ResponseEntity.ok(result);
    }

    /**
     * 新增关系
     */
    @PostMapping
    public ResponseEntity<Map<String, Object>> save(@RequestBody ForeignRelation relation) {
        boolean success = foreignRelationService.save(relation);

        Map<String, Object> result = new HashMap<>();
        result.put("code", success ? 200 : 500);
        result.put("message", success ? "Relation created successfully" : "Failed to create relation");
        result.put("data", relation);

        return ResponseEntity.ok(result);
    }

    /**
     * 更新关系
     */
    @PutMapping("/{id}")
    public ResponseEntity<Map<String, Object>> update(
            @PathVariable Long id,
            @RequestBody ForeignRelation relation) {

        relation.setId(id);
        boolean success = foreignRelationService.updateById(relation);

        Map<String, Object> result = new HashMap<>();
        result.put("code", success ? 200 : 500);
        result.put("message", success ? "Relation updated successfully" : "Failed to update relation");
        result.put("data", relation);

        return ResponseEntity.ok(result);
    }

    /**
     * 删除关系
     */
    @DeleteMapping("/{id}")
    public ResponseEntity<Map<String, Object>> delete(@PathVariable Long id) {
        boolean success = foreignRelationService.deleteById(id);

        Map<String, Object> result = new HashMap<>();
        result.put("code", success ? 200 : 500);
        result.put("message", success ? "Relation deleted successfully" : "Failed to delete relation");

        return ResponseEntity.ok(result);
    }

    /**
     * 批量删除关系
     */
    @DeleteMapping("/batch")
    public ResponseEntity<Map<String, Object>> deleteBatch(@RequestBody List<Long> ids) {
        boolean success = foreignRelationService.deleteByIds(ids);

        Map<String, Object> result = new HashMap<>();
        result.put("code", success ? 200 : 500);
        result.put("message", success ? "Relations deleted successfully" : "Failed to delete relations");

        return ResponseEntity.ok(result);
    }
}
